import{_ as t,o as e,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F02: 營業現金流與獲利品質 - 財務分析專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/4967_十銓/20260428/F02_營業現金流與獲利品質_財務分析專家.md","filePath":"審計報告庫/財務審計/4967_十銓/20260428/F02_營業現金流與獲利品質_財務分析專家.md"}'),n={name:"審計報告庫/財務審計/4967_十銓/20260428/F02_營業現金流與獲利品質_財務分析專家.md"};function r(o,a,s,c,h,_){return e(),i("div",null,[...a[0]||(a[0]=[l('<p>我已讀取 03_審計專家_任務執行與技術協議.md，準備執行 FA-Batch-F1 任務。</p><h1 id="f02-營業現金流與獲利品質-財務分析專家審計報告" tabindex="-1">F02: 營業現金流與獲利品質 - 財務分析專家審計報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-財務分析專家審計報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 - 財務分析專家審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：2025年淨利11.1億創新高，但CFO為-35.2億，比值-317%，獲利無現金支撐。主因存貨+33.7億、應收+32.0億侵佔營運資金。</li><li><strong>風險評級</strong>：高 —「有獲利無現金」為最危險財務訊號，依賴外部融資填補缺口。</li><li><strong>數據時效</strong>：截至2025年12月年度財報。</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：CFO -35.2億 vs 淨利11.1億（比值-317%）；FCF -36.3億（2024年+8.9億）；折舊僅4.5億（佔淨利4%）；現金從24.7億降至7.1億（-71%），短期借款從9.6億增至32.3億。</li><li><strong>診斷見解</strong>：典型「紙上富貴」。淨利11.1億無一分轉化為營業現金流入，營運資金淨流出50.0億。公司靠外部融資（短期+22.7億、長期+13.0億）支撐營運週轉，利率環境下財務費用壓力加劇。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="獲利含金量指標-cfo-net-income" tabindex="-1">獲利含金量指標（CFO/Net Income） <a class="header-anchor" href="#獲利含金量指標-cfo-net-income" aria-label="Permalink to &quot;獲利含金量指標（CFO/Net Income）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025年比值-317%（歷史最差）；2024年+176%（正常）；2023年-181%（異常）。2025存貨+58%（58.2→91.9億），應收+308%（10.1→41.3億）。</li><li><strong>深度見解</strong>：2025與2023均CFO為負但成因不同。2023為記憶體低迷期存貨堆積；2025為營收停滯下大量備貨，且應收增幅遠超營收增幅（+2.5%），暗示下游客戶付款條件被大幅放寬或期末集中出貨。</li></ul><h3 id="非現金項目核實" tabindex="-1">非現金項目核實 <a class="header-anchor" href="#非現金項目核實" aria-label="Permalink to &quot;非現金項目核實&quot;">​</a></h3><ul><li><strong>核心重點</strong>：折舊攤銷4.5億，佔淨利4.1%。PPE淨額4.56億（佔總資產3%）。營運資金變動-50.0億（佔淨利450%），遠超折舊。</li><li><strong>深度見解</strong>：十銓為輕資本模組廠，折舊對獲利美化極低。現金流惡化核心在應收與存貨管理，非資本支出。獲利品質完全取決於營運資金管控能力。</li></ul><h3 id="自由現金流穿透" tabindex="-1">自由現金流穿透 <a class="header-anchor" href="#自由現金流穿透" aria-label="Permalink to &quot;自由現金流穿透&quot;">​</a></h3><ul><li><strong>核心重點</strong>：FCF = -36.3億（CFO -35.2億 - CapEx 1.05億）。現金股利2.55億（佔淨利23%），資金實為借款。融資流入35.1億全數填補營運缺口。</li><li><strong>深度見解</strong>：FCF連續為負，公司無法靠自身經營產生現金，分紅2.55億實為「借錢分紅」。若2026年應收與存貨未能有效去化，融資需求將持續攀升，壓縮未來分紅空間。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一 — 有獲利無現金</strong>：淨利11.1億但CFO-35.2億，差額46.3億。帳面獲利鎖在應收（+32億）與存貨（+33.7億）中。若2027年記憶體報價反轉，存貨跌價損失可能一次性侵蝕數年累計獲利，應收減損形成雙重打擊。公司連續兩年（2023、2025）CFO為負，顯示獲利品質反覆惡化，非一次性異常。</li><li><strong>空頭風險二 — 流動性惡化</strong>：現金7.1億 vs 短期借款32.3億。速動比率僅52%（(144.2-91.9)/100.8），低於安全水準。若下游需求驟降或融資收緊，面臨短期流動性壓力。利息費用+52%（3,110萬→4,737萬），融資成本持續攀升。借錢分紅2.55億並非常態，壓縮未來股利空間。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind (TaiwanStockCashFlowsStatement)</strong>：OK（2021-2025各季CFO、折舊、營運資金數據）</li><li><strong>FinMind (TaiwanStockBalanceSheet)</strong>：OK（應收、存貨、現金、借款各季數據）</li><li><strong>yfinance (4967.TW)</strong>：OK（2022-2025年度現金流量表完整數據）</li><li><strong>關鍵核對碼</strong>： <ul><li>2025 CFO: -3,520,704,000 TWD</li><li>2025 Net Income: 1,109,873,000 TWD</li><li>2025 Change In Inventory: -3,368,231,000</li><li>2025 Change In Receivables: -3,202,588,000</li><li>2025 Change In Working Capital: -5,002,065,000</li><li>2025 FCF: -3,625,521,000</li></ul></li></ul>',19)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
